parameters.jsCode:
// Sitemap XML parsen und neueste Seite erkennen
const xml = $input.first().json.data || $input.first().json.body || '';

// Alle <url>-Blöcke extrahieren
const entries = [];
const urlBlockRegex = /<url>([\s\S]*?)<\/url>/g;
let match;
while ((match = urlBlockRegex.exec(xml)) !== null) {
  const block = match[1];
  const locMatch = block.match(/<loc>([^<]+)<\/loc>/);
  const modMatch = block.match(/<lastmod>([^<]+)<\/lastmod>/);
  if (locMatch) {
    entries.push({
      url: locMatch[1].trim(),
      lastmod: modMatch ? modMatch[2 - 1].trim() : ''
    });
  }
}

const totalCount = entries.length;
if (totalCount === 0) {
  return [{ json: { hasNew: false, debug: 'Keine URLs gefunden' } }];
}

// Neuester Eintrag = letzter in der Sitemap
const newest = entries[entries.length - 1];

// Gespeicherten Stand laden
const stored = $getWorkflowStaticData('global');
const prevCount = stored.urlCount || 0;
const prevLastUrl = stored.lastUrl || '';

// Neu wenn Anzahl gestiegen oder URL anders
const hasNew = totalCount > prevCount || newest.url !== prevLastUrl;

if (hasNew) {
  // Stand aktualisieren
  stored.urlCount = totalCount;
  stored.lastUrl = newest.url;

  // Lesbaren Seitennamen erzeugen
  const filename = newest.url.split('/').pop().replace('.html', '');
  const pageName = filename.replace(/-/g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase());

  return [{ json: {
    hasNew: true,
    pageUrl: newest.url,
    pageLastmod: newest.lastmod,
    pageName,
    totalCount,
    prevCount,
    newCount: totalCount - prevCount
  }}];
}

return [{ json: { hasNew: false, totalCount, lastUrl: newest.url } }];

